// core/tree/engine/TreeExpansion.ts

import type { TreeNode } from '../models/TreeNode';
import type { ExpandedKeys } from '../models/ExpandedKeys';
import { walkTree } from './TreeTraversal';

/**
 * Toggle expansion for a single node key.
 */
export function toggleExpansion(
  expandedKeys: ExpandedKeys | null | undefined,
  key: string
): ExpandedKeys {
  const next: ExpandedKeys = { ...(expandedKeys || {}) };

  if (next[key]) {
    delete next[key];
  } else {
    next[key] = true;
  }

  return next;
}

/**
 * Expand all expandable nodes.
 */
export function expandAll(nodes: TreeNode[] | undefined): ExpandedKeys {
  const expanded: ExpandedKeys = {};

  if (!nodes) return expanded;

  walkTree(nodes, (node) => {
    if (node.children && node.children.length) {
      expanded[node.key] = true;
    }
  });

  return expanded;
}

/**
 * Collapse all nodes.
 */
export function collapseAll(): ExpandedKeys {
  return {};
}
